var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"07:30 AM 전략특수전사령부 휘하 <color=#ffd34c>제 7 델타분견대</color> \\n통칭 <color=#ffd34c>델타 세븐</color> 기함 <color=#ffd34c>뉴 오하이오 작전실</color>      ","JPN":"07:30 AM 戦略特殊戦司令部所属<color=#ffd34c>第7デルタセブン支隊</color>\\n通称<color=#ffd34c>デルタセブン</color>艦船<color=#ffd34c>ニューオハイオ作戦室</color>     ","ENG":"[[","TWN":"07:30 AM 戰略特戰司令部指揮所屬 <color=#ffd34c>第七三角洲分遣隊</color> \\n通稱 <color=#ffd34c>第七三角洲</color> 司令艦 <color=#ffd34c>新俄亥俄作戰室</color>","THA":"7.30 น. คำสั่งปฏิบัติการพิเศษเชิงยุทธวิธี <color=#ffd34c>หน่วยเดลต้าที่ 7</color>\\nหรือ <color=#ffd34c>เดลต้าเซเว่น</color><color=#ffd34c>ห้องยุทธศาสตร์นิวโอไฮโอ</color>      ","VTN":"7:30 sáng, Bộ Chỉ Huy Tác Chiến Đặc Biệt, <color=#ffd34c>Biệt Đội Delta Số 7</color>\\nA.K.A. <color=#ffd34c>Delta Seven</color> Tàu Đô Đốc <color=#ffd34c>Phòng Chiến Lược Tân Ohio</color>      ","SCN":"07:30 AM 战略特战司令部所属<color=#ffd34c>德尔塔分遣队</color> \\n统称<color=#ffd34c>德尔塔部队</color>指挥舰<color=#ffd34c>伊欧作战室</color>      ","DEU":"[[","FRA":"7\xA0h\xA030, commandement des opérations stratégiques spéciales, <color=#ffd34c>7e\xA0détachement Delta</color>\\nalias <color=#ffd34c>Delta Seven</color>, <color=#ffd34c>salle des opérations du vaisseau amiral New\xA0Ohio</color>      "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"마리아 안토노프, 카일 웡, 실비아 레나 쿠퍼 \\n<color=#ffd34c>CSE Level 1</color>","JPN":"マリア・アントノフ、カイル・ウォン、シルビア・レナ・クーパー\\n<color=#ffd34c>CSE Level 1</color>","ENG":"[[","TWN":"瑪麗亞． 安東諾夫，希爾維亞． 蕾娜．庫博 \\n<color=#ffd34c>CSE Level 1</color>","THA":"มาเรีย แอนโทนอฟ ไคล์ หว่อง ซิลเวีย เลน่า คูเปอร\\n<color=#ffd34c>ระดับ CSE 1</color>์","VTN":"Maria Antonov, Kyle Wong, Sylvia Lena Cooper\\n<color=#ffd34c>CSE Cấp 1</color>","SCN":"玛丽亚·安东，凯尔，希尔薇娅\\n<color=#ffd34c>CSE Level 1</color>","DEU":"[[","FRA":"Maria\xA0Antonov, Kyle\xA0Wong, Sylvia\xA0Lena\xA0Cooper\\n<color=#ffd34c>ECM niveau\xA01</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다들 모였나? 작전 브리핑을 시작하려고 하는데.","JPN":"全員集まったか？　作戦のブリーフィングを始めたいのだが。","ENG":"Is everyone here? I want to start the operation briefing.","TWN":"大家都到齊了？我要開始作戰簡要說明了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하암...... 마리아 아줌마, 뭐 이런 꼭두새벽부터 사람을 오라 가라 그래?","JPN":"ふあ～マリアおばさん、こんな朝っぱらから集まる必要あるの？","ENG":"*Yawn* Maria, did you really have to wake me up so early in the morning?","TWN":"（哈欠）哈啊……瑪麗亞大嬸，幹嘛大清早就把人叫來啊？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소장님께 말버릇이 그게 뭡니까! 실비아씨.","JPN":"少将に対し、なんて失礼な言い方を！　シルビアさん。","ENG":"Sylvia, you're speaking to the Major General.","TWN":"你這是和少將說話的口氣嗎！希爾維亞小姐。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 오전 7시면 일반인들도 충분히 활동을 시작할 시간입니다. 새벽이 아니에요!","JPN":"それに、午前7時は一般人が普通に活動を始める時間帯ですよ。\\n朝っぱらだなんて！　","ENG":"And 7 a.m. is not that early. Most people start their day around this time.","TWN":"而且早上7點一般人早就開始活動，不是大清早了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐래? 난 11시 기상 새벽 4시 취침이 디폴트거든.","JPN":"関係ないし。\\nアタシは11時に起きて、夜中の4時に寝るのがフツーなのよ。","ENG":"Not me. I wake up at 11 a.m. and go to bed at 4 a.m.","TWN":"你說什麼？早上11點起床淩晨四點就寢才是我的日常。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨의 개인적인 활동 선호시간 따위는 전혀 궁금하지 않습니다.","JPN":"シルビアさんの個人的な活動時間なんてまったく興味ありません。","ENG":"No one's interested in your personal daily routine, Sylvia.","TWN":"我對希爾維亞小姐個人的活動時間偏好沒有興趣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이제 실비아씨도 부대의 일원이 된 이상 규율과 규칙의 엄정함을 존중하는 태도를 가져야 합니다.","JPN":"シルビアさんも部隊の一員になった以上、\\n厳正な規律と規則を尊重するべきです。","ENG":"Now that you're a member of this unit, you must follow its rules and regulations like everyone else.","TWN":"但既然希爾維亞小姐現在也成為了部隊的一員，就必須尊重紀律與規則的嚴正性。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"난 너랑 다르게 <color=#ffd34c>민간직</color> 군사 협조 요원이라서 말이야.","JPN":"アタシは君と違って、<color=#ffd34c>民間</color>の軍事協力要員なの。","ENG":"But unlike you, I'm a <color=#ffd34c>civilian</color> collaborator.","TWN":"因為我和你不一樣，是<color=#ffd34c>民間</color>軍事協助要員啊，"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내 개인적인 <color=#ffd34c>엄정한</color> 규율에 착실히 따르고 있으니까 신경 좀 꺼줄래?","JPN":"独自の<color=#ffd34c>厳正な</color>規律を順守してるんだから、茶々入れないでくれる？","ENG":"And I'm following <color=#ffd34c>rules</color> of my own, so get off my back, will you?","TWN":"我會確實遵守自己<color=#ffd34c>嚴肅的</color>紀律，可以不要囉嗦我的事嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어쩔 수 없군요. 저도 이런 방법은 쓰고 싶지 않았지만......","JPN":"仕方ないですね。僕もこんなやり方は避けたかったのですが……","ENG":"Fine. I really didn't want to do this,","TWN":"沒辦法。我也不太想用這種手段，不過……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 다 실비아 씨가 자초한 일이니 그렇게 아십시오.","JPN":"すべてシルビアさん自ら招いたことですから、ご承知おきを。","ENG":"but you're leaving me little choice, Sylvia.","TWN":"請希爾維亞小姐知道，這都是妳自找的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 무슨 짓을 하려고......","JPN":"え？　何をするつもり……","ENG":"What? What are you trying to—","TWN":"什麼？你想做什……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>경고!</color>","JPN":"<color=#ffd34c>警告！</color>","ENG":"<color=#ffd34c>Warning!</color>","TWN":"<color=#ffd34c>警告！</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>강제 권한 개입에 의해 임시적으로 작동을 정지합니다.</color>","JPN":"<color=#ffd34c>強制措置により、作動を一時停止します。</color>","ENG":"<color=#ffd34c>The system's operation has been temporarily put to a halt by forced intervention.</color>","TWN":"<color=#ffd34c>由於強制權限干涉，暫時終止運作。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};